  "required": ["model", "res_ids", "values"]
}

{
  "type": "object",
  "properties": {
    "model": {"type": "string", "description": "Technical model name"},
    "res_ids": {"type": "array", "items": {"type": "integer"}, "description": "Target record database IDs"},
    "method": {"type": "string", "description": "Method name to call (e.g. \"action_confirm\")"},
    "args": {"type": "array", "description": "Positional method arguments"},
    "kwargs": {"type": "object", "description": "Keyword method arguments"}
  },
  "required": ["model", "res_ids", "method"]
}

{
  "type": "object",
  "properties": {
    "query": {"type": "string", "description": "Pattern regex to search for"},
    "path_filter": {"type": "string", "description": "Glob pattern to filter paths (e.g., \"*.py\")"}
  },
  "required": ["query"]
}

{
  "type": "object",
  "properties": {
    "filepath": {"type": "string", "description": "Relative path to file in project"},
    "start_line": {"type": "integer", "description": "Start line (1-indexed)", "default": 1},
    "end_line": {"type": "integer", "description": "End line (1-indexed)", "default": 100}
  },
  "required": ["filepath"]
}

{
  "type": "object",
  "properties": {
    "code": {"type": "string", "description": "Python block to execute. Pre-loaded: env, user, Command, base64, io, BytesIO, StringIO, xlrd, openpyxl, json, re, math, datetime, date, timedelta, defaultdict, Counter, print, read_excel(attachment_id). Never write import statements. Use return (not print) to expose data back to the AI."}
  },
  "required": ["code"]
}

{
  "type": "object",
  "properties": {
    "model": {"type": "string", "description": "Technical model name (e.g. \"sale.order\")"},
    "record_id": {"type": "integer", "description": "ID of the record to post on"},
    "body": {"type": "string", "description": "Message body (plain text or HTML)"},
    "message_type": {"type": "string", "description": "comment (visible, sends email) or internal (private note)", "default": "comment"}
  },
  "required": ["model", "record_id", "body"]
}

{
  "type": "object",
  "properties": {
    "attachment_id": {"type": "integer", "description": "ID of the ir.attachment record"},
    "include_data": {"type": "boolean", "description": "Include base64 content (default true, capped at 1MB)"}
  },
  "required": ["attachment_id"]
}

{
  "type": "object",
  "properties": {
    "model": {"type": "string", "description": "Odoo model (e.g. product.template)"},
