    "has_header": {"type": "boolean", "description": "Whether first row is field names (default: true)", "default": true}
  },
  "required": ["attachment_id", "model"]
}

{
  "type": "object",
  "properties": {
    "name": {"type": "string", "description": "Chart title shown in MCP Charts app"},
    "data_code": {"type": "string", "description": "Python script with Odoo ORM access (env, user available). Must end with: return {complete ECharts options dict with data embedded}. Use env['model'].read_group() or search_read() to fetch data inside this script."}
  },
  "required": ["name", "data_code"]
}
